sql:
SELECT COUNT(parser_id) AS active_parser_count
FROM parsers
WHERE is_active = 1;

SELECT COUNT(*) AS total_active_event_messages
FROM event_messages
WHERE is_active = 1;

SELECT event_message_string, description, COUNT(event_message_id) AS message_count
FROM event_messages
GROUP BY event_message_string, description;

SELECT COUNT(*) AS active_event_sources
FROM event_sources
WHERE is_active = 1;

SELECT event_source_name, description
FROM event_sources
WHERE is_active = 1;

